phase1.code:
class Person {
    // Private fields — hidden from outside
    private String name;
    private int age;

    // Constructor
    Person(String name, int age) {
        this.name = name;
        setAge(age);  // Use setter for validation
    }

    // Getters (public)
    public String getName() {
        return name;
    }

    public int getAge() {
        return age;
    }

    // Setters with validation
    public void setName(String name) {
        if (name != null && !name.trim().isEmpty()) {
            this.name = name;
        } else {
            System.out.println("Invalid name!");
        }
    }

    public void setAge(int age) {
        if (age >= 0 && age <= 150) {
            this.age = age;
        } else {
            System.out.println("Invalid age! Must be 0-150.");
        }
    }

    // Public method
    public void displayInfo() {
        System.out.println("Name: " + name + ", Age: " + age);
    }
}

public class EncapsulationExample {
    public static void main(String[] args) {
        Person person = new Person("Alice", 25);

        // Accessing through getters
        System.out.println("Name: " + person.getName());
        System.out.println("Age: " + person.getAge());

        // Using setters
        person.setName("Bob");
        person.setAge(30);
        person.displayInfo();

        // Trying invalid values
        person.setAge(-5);   // Invalid!
        person.setAge(200);  // Invalid!

        // Can't access private fields directly:
        // person.name = "Charlie";  // ERROR!
        // person.age = 99;          // ERROR!
    }
}

phase2.brokenCode:
class Person {
    private String name;
    private int age;

    Person(String name, int age) {
        this.name = name;
        this.age = age;
    }
}

public class EncapsulationExample {
    public static void main(String[] args) {
        Person person = new Person("Alice", 25);

        // Trying to access private field directly
        System.out.println(person.name);
        person.age = 30;
    }
}

phase2.explanation:
You can't access private fields from outside the class! This is the ENTIRE POINT of encapsulation.

To fix, add public getters and setters:
public String getName() { return name; }
public void setName(String name) { this.name = name; }

Then use: person.getName() and person.setName("Bob")

Private means private — only the class itself can touch it.

phase3.solution:
class BankAccount {
    private String owner;
    private double balance;

    BankAccount(String owner, double initialBalance) {
        this.owner = owner;
        this.balance = initialBalance;
    }

    public String getOwner() {
        return owner;
    }

    public double getBalance() {
        return balance;
    }

    public void deposit(double amount) {
        if (amount > 0) {
            balance += amount;
            System.out.println("Deposited $" + amount);
        } else {
            System.out.println("Deposit must be positive!");
        }
    }

    public void withdraw(double amount) {
        if (amount > 0 && amount <= balance) {
            balance -= amount;
            System.out.println("Withdrew $" + amount);
        } else {
            System.out.println("Insufficient balance or invalid amount!");
        }
    }

    public void displayInfo() {
        System.out.println("Owner: " + owner + ", Balance: $" + balance);
    }
}

public class Main {
    public static void main(String[] args) {
        BankAccount account = new BankAccount("Alice", 1000);
        account.deposit(500);
        account.withdraw(200);
        account.displayInfo();
        account.withdraw(1500);  // Should fail
    }
}
